};

function stockHeadline(stock){
  const h = stock.history;
  if(!h || h.length < 2) return null;
  const prev = h[h.length-2], cur = h[h.length-1];
  const chgPct = prev > 0 ? ((cur-prev)/prev*100) : 0;
  const dir = chgPct > 0 ? 'â–²' : chgPct < 0 ? 'â–¼' : 'â€”';
  const cls = chgPct > 0 ? 'up' : chgPct < 0 ? 'dn' : 'flat';
  return {icon:'ðŸ“Š', text:`${stock.name} ${dir} ${Math.abs(chgPct).toFixed(1)}% â€” ${chgPct>2?'beats estimates':chgPct<-2?'misses guidance':'in line with forecasts'}`, chg:chgPct, cls, type:'stock'};
}

function cryptoHeadline(coin){
  const h = coin.history;
  if(!h || h.length < 2) return null;
  const prev = h[h.length-2], cur = h[h.length-1];
  const chgPct = prev > 0 ? ((cur-prev)/prev*100) : 0;
  const dir = chgPct > 0 ? 'â–²' : chgPct < 0 ? 'â–¼' : 'â€”';
  return {icon:'â‚¿', text:`${coin.name} ${dir} ${Math.abs(chgPct).toFixed(1)}% â€” ${chgPct>5?'bulls return':chgPct<-5?'selloff accelerates':'range-bound trading'}`, chg:chgPct, cls:chgPct>0?'up':'dn', type:'crypto'};
}

function generateNewsHeadlines(inv){
  const headlines = [];
  if(inv && inv.stocks){
    for(const s of inv.stocks){
      const h = stockHeadline(s);
      if(h) headlines.push(h);
    }
  }
  if(inv && inv.cryptos){
    for(const c of inv.cryptos){
      const h = cryptoHeadline(c);
      if(h) headlines.push(h);
    }
  }
  const macroItem = pick(ECONOMIC_FLAVOR_POOL);
  headlines.push({icon:macroItem.icon, text:macroItem.text, chg:null, cls:'flat', type:'macro'});
  const reItem = pick(REAL_ESTATE_POOL);
  headlines.push({icon:reItem.icon, text:reItem.text, chg:null, cls:'flat', type:'realty'});
  while(headlines.length < 8){
    const m = pick(ECONOMIC_FLAVOR_POOL);
    headlines.push({icon:m.icon, text:m.text, chg:null, cls:'flat', type:'macro'});
  }
  return headlines;
}

function renderNewsFeed(headlines){
  const feed = document.getElementById('news-feed');
  if(!feed) return;
  const items = [...headlines, ...headlines];
  feed.innerHTML = items.map(h=>`<div class="news-item ${h.type||'macro'}"><span class="ni-icon">${h.icon}</span><span class="ni-text">${h.text}</span>${h.chg!==null?`<span class="ni-chg ${h.cls||'flat'}">${h.chg>=0?'+':''}${h.chg.toFixed(1)}%</span>`:''}</div>`).join('');
  feed.style.animation='none';
  void feed.offsetWidth;
  feed.style.animation='scrollUp 20s linear infinite';
}

function renderNewsTicker(inv){
  const ticker = document.getElementById('news-ticker');
  if(!ticker || !inv) return;
  let items = [];
  for(const s of (inv.stocks||[])){
    const h = s.history;
    const prev = h&&h.length>1?h[h.length-2]:s.price;
    const chg = prev>0?(s.price-prev)/prev*100:0;
    const cls = chg>0?'tk-up':chg<0?'tk-dn':'';
    items.push(`<span class="tk-item"><span class="tk-sym">${s.id}</span> <span class="tk-val">$${s.price.toFixed(0)}</span> <span class="${cls}">${chg>=0?'+':''}${chg.toFixed(1)}%</span></span>`);
  }
  for(const c of (inv.cryptos||[])){
    const h = c.history;
    const prev = h&&h.length>1?h[h.length-2]:c.price;
    const chg = prev>0?(c.price-prev)/prev*100:0;
    const cls = chg>0?'tk-up':chg<0?'tk-dn':'';
    const fmtP = c.price>=1000?'$'+(c.price/1000).toFixed(1)+'k':c.price>=1?'$'+c.price.toFixed(0):'$'+c.price.toFixed(4);
    items.push(`<span class="tk-item"><span class="tk-sym">${c.id}</span> <span class="tk-val">${fmtP}</span> <span class="${cls}">${chg>=0?'+':''}${chg.toFixed(1)}%</span></span>`);
  }
  if(!items.length) items.push(`<span class="tk-item"><span class="tk-sym">FINNEWS</span> <span class="tk-val">Markets are open</span></span>`);
  ticker.innerHTML = [...items,...items].join(' Â· ');
  ticker.style.animation='none';
  void ticker.offsetWidth;
  ticker.style.animation='tickerScroll 30s linear infinite';
}

function updateNewsChannel(){
  const inv = GS.inv;
  if(!inv) return;
  const headlines = generateNewsHeadlines(inv);
  renderNewsFeed(headlines);
  renderNewsTicker(inv);
}

function initNewsChannel(){
  updateNewsChannel();
}

