function buildJobChangeEvent(c){
  const smarts=Math.round(c.smarts);
  const allJobs=getAvailableJobs(c);
  // Prefer jobs that pay more than current; fallback to best available if already at top
  let candidates=allJobs.filter(j=>j.min>(c.salary||0)*0.85);
  if(!candidates.length) candidates=allJobs.slice(0,3);
  const jobs=candidates.slice(0,4);
  const desc=`Your annual career window is open. Your Smarts score is ${smarts} â€” that's your ${smarts}% success rate per application.${c.jobTitle?` You're currently a ${c.jobTitle} earning ${fmt$(c.salary)}/yr.`:''} This window closes after you decide.`;
  return {
    id:'career_window',
    title:'Annual Career Opportunity',
    cat:'milestone',
    icon:'ðŸ’¼',
    desc,
    choices:[
      ...jobs.map(job=>({
        text:`${job.name} (${job.sector}) â€” ${fmt$(job.min)}â€“${fmt$(job.max)}/yr  [${smarts}% success]`,
        fn(ch){
          if(Math.random()*100<smarts){applyForJob(ch,job);return`ðŸŽ‰ Hired as ${job.name}! Starting salary: ${fmt$(ch.salary)}/yr`;}
          return`â�Œ Rejected for ${job.name}. Raise your Smarts for better odds next year.`;
        }
      })),
      {text:`Stay at ${c.jobTitle||'current position'} (${fmt$(c.salary||0)}/yr)`,fn(){return'Staying put. Next career window opens in 1 year.'}},
    ],
  };
}

