function drawMiniChart(canvasId, history, currentPrice){
  const canvas=document.getElementById(canvasId);
  if(!canvas) return;
  const dpr=window.devicePixelRatio||1;
  const W=Math.max(10, canvas.parentElement.clientWidth-16);
  const H=46;
  canvas.width=W*dpr; canvas.height=H*dpr;
  canvas.style.width=W+'px'; canvas.style.height=H+'px';
  const ctx=canvas.getContext('2d');
  ctx.scale(dpr,dpr);
  if(!history||history.length<2){
    ctx.strokeStyle='#2e4a2e'; ctx.lineWidth=1.5;
    ctx.beginPath(); ctx.moveTo(0,H/2); ctx.lineTo(W,H/2); ctx.stroke();
    return;
  }
  const mn=Math.min(...history), mx=Math.max(...history);
  const range=mx-mn||Math.abs(currentPrice)*0.01||1;
  const pad=4;
  const pts=history.map((v,i)=>[i/(history.length-1)*(W-pad*2)+pad, H-pad-((v-mn)/range)*(H-pad*2)]);
  const isUp=history[history.length-1]>=history[0];
  const col=isUp?'#00c853':'#ff3d3d';
  // Gradient fill
  const grad=ctx.createLinearGradient(0,0,0,H);
  grad.addColorStop(0, isUp?'rgba(0,200,83,.28)':'rgba(255,61,61,.28)');
  grad.addColorStop(1,'rgba(0,0,0,0)');
  ctx.beginPath(); ctx.moveTo(pts[0][0],pts[0][1]);
  for(let i=1;i<pts.length;i++) ctx.lineTo(pts[i][0],pts[i][1]);
  ctx.lineTo(pts[pts.length-1][0],H); ctx.lineTo(pts[0][0],H); ctx.closePath();
  ctx.fillStyle=grad; ctx.fill();
  // Line
  ctx.beginPath(); ctx.moveTo(pts[0][0],pts[0][1]);
  for(let i=1;i<pts.length;i++) ctx.lineTo(pts[i][0],pts[i][1]);
  ctx.strokeStyle=col; ctx.lineWidth=1.5; ctx.lineJoin='round'; ctx.stroke();
  // End dot
  const ep=pts[pts.length-1];
  ctx.beginPath(); ctx.arc(ep[0],ep[1],3,0,Math.PI*2);
  ctx.fillStyle=col; ctx.fill();
  // Start dot (faint)
  ctx.beginPath(); ctx.arc(pts[0][0],pts[0][1],2,0,Math.PI*2);
  ctx.fillStyle='rgba(255,255,255,.3)'; ctx.fill();
}

function buildAssetCardHTML(id, name, idLabel, price, fmtPrice, history, ownedLine, buyBtn, sellBtn, sinceChgPct, lastChgPct){
  const sc=sinceChgPct>=0?'chg-pos':'chg-neg';
